// Response comes directly from the Express API as JSON
const result = $input.first().json;

if (!result.ok) {
  return [{ json: { ok: false, error: result.error || 'Scraper returned error', details: result } }];
}

const data = result.data || {};
const extractedAt = result.extractedAt;

const notifications = (data.notifications || []).map(n => ({
  json: { ...n, _type: 'notification', _extractedAt: extractedAt, _studentName: data.studentName }
}));

const classEvents = (data.classEvents || [])
  .filter(e => !e.includes('לא נמצאו'))
  .map(e => ({
    json: { raw: e, _type: 'classEvent', _extractedAt: extractedAt, _studentName: data.studentName }
  }));

const all = [...notifications, ...classEvents];

if (all.length === 0) {
  return [{ json: { ok: true, count: 0, extractedAt, message: 'No items found', studentName: data.studentName } }];
}

return all;
